#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_STRIDED 1

typedef short cl_half2[2];

#ifdef ENABLE_DP
typedef double class_T;
#else
#ifdef ENABLE_HP
typedef cl_half2 class_T;
#else
typedef float class_T;
#endif
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef BLOCK_STRIDED
#define STRIDE blockdim
#else
#define STRIDE 1
#endif

__attribute__((noinline))
class_T bench_block(class_T* data, class_T f) {
    class_T sum = 0;

#ifdef ENABLE_HP
    class_T t_val = data[0];
    class_T f_val = f;

    for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
        t_val = t_val * t_val + f_val;
    }
    sum += t_val;
#else
    class_T t = data[0];

    for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
        t = t * t + f;
    }
    sum += t;
#endif

    return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* src) {
    size_t global_id = get_global_id(0);
    size_t local_id = get_local_id(0);
    size_t group_id = get_group_id(0);

    size_t stride = STRIDE * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t start_index = (group_id * stride) + (local_id * ELEMENTS_PER_THREAD * FUSION_DEGREE);

    class_T local_sum = 0;

    for (int fusion_idx = 0; fusion_idx < FUSION_DEGREE; fusion_idx++) {
        for (int elem_idx = 0; elem_idx < ELEMENTS_PER_THREAD; elem_idx++) {
            size_t idx = start_index + (fusion_idx * ELEMENTS_PER_THREAD) + elem_idx;

            if (idx < get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE) {
                class_T val = src[idx];
                class_T f = seed;

                class_T t = val;
                for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
                    t = t * t + f;
                }
                local_sum += t;
            }
        }
    }

    if (FUSION_DEGREE > 1 || ELEMENTS_PER_THREAD > 1) {
        src[start_index] = local_sum;
    } else {
        src[global_id] = local_sum;
    }
}
